fun solve(grid: Array<Array<Long>>, k: Long): Long {
    val m = grid.size
    val n = grid[0].size
    val visited = Array(m) { BooleanArray(n) }
    var count = 0L

    val directions = listOf(
        Pair(0, 1),
        Pair(1, 0),
        Pair(0, -1),
        Pair(-1, 0)
    )

    for (i in 0 until m) {
        for (j in 0 until n) {
            if (grid[i][j] > 0 && !visited[i][j]) {
                val queue = LinkedList<Pair<Int, Int>>()
                queue.add(Pair(i, j))
                visited[i][j] = true
                var sum = grid[i][j]

                while (queue.isNotEmpty()) {
                    val (x, y) = queue.pollFirst()
                    for (dir in directions) {
                        val dx = dir.first
                        val dy = dir.second
                        val nx = x + dx
                        val ny = y + dy
                        if (nx in 0..m - 1 && ny in 0..n - 1 && !visited[nx][ny] && grid[nx][ny] > 0) {
                            visited[nx][ny] = true
                            sum += grid[nx][ny]
                            queue.add(Pair(nx, ny))
                        }
                    }
                }

                if (sum % k == 0L) {
                    count++
                }
            }
        }
    }

    return count
}
